mapper.select:
SELECT
    er.record_id, er.elder_id, er.account_id, er.expense_type, er.transaction_type,
    er.amount, er.description, er.related_id, er.related_type,
    er.balance_before, er.balance_after,
    er.create_by, er.create_time, er.update_by, er.update_time, er.remark,
    ei.elder_name,
    pi.institution_name
FROM expense_record er
LEFT JOIN elder_info ei ON er.elder_id = ei.elder_id
LEFT JOIN account_info ai ON er.account_id = ai.account_id
LEFT JOIN pension_institution pi ON ai.institution_id = pi.institution_id

     and er.elder_id = #{elderId}
     and er.account_id = #{accountId}
     and er.expense_type = #{expenseType}
     and er.transaction_type = #{transactionType}
     and er.amount = #{amount}
     and er.description like concat('%', #{description}, '%')
     and er.related_id = #{relatedId}
     and er.related_type = #{relatedType}

ORDER BY er.create_time DESC

mapper.update:
update expense_record
elder_id = #{elderId}, account_id = #{accountId}, expense_type = #{expenseType}, transaction_type = #{transactionType}, amount = #{amount}, description = #{description}, related_id = #{relatedId}, related_type = #{relatedType}, balance_before = #{balanceBefore}, balance_after = #{balanceAfter}, create_by = #{createBy}, create_time = #{createTime}, update_by = #{updateBy}, update_time = #{updateTime}, remark = #{remark},
where record_id = #{recordId}
